Add timeline auto-dump to disk when a plan completes.

## File 1: plan-panel.ts

### 1a. Add at top after existing imports
```typescript
import { writeFileSync } from "node:fs";
```

### 1b. Add session ID variable near other module-level state (near `_timeline`):
```typescript
let _sessionId: string | null = null;
```

### 1c. In `setupPlanPanel()` function — add at the beginning:
```typescript
_sessionId = Date.now().toString(36) + Math.random().toString(36).slice(2, 8);
```

### 1d. In `clearPlanPanel()` function — add at the beginning:
```typescript
dumpTimelineToDisk();
_sessionId = null;
```

### 1e. Add dumpTimelineToDisk function:
```typescript
export function dumpTimelineToDisk(): void {
    if (_timeline.length === 0) return;
    const id = _sessionId ?? "unknown";
    const path = `/tmp/orchestrator-timeline-${id}.json`;
    try {
        const data = JSON.stringify({
            sessionId: id,
            recordedAt: Date.now(),
            totalFrames: _timeline.length,
            events: getTimeline(),
            diff: getTimelineDiff(),
        }, null, 2);
        writeFileSync(path, data, "utf-8");
        console.error(`[timeline] ${_timeline.length} frames → ${path}`);
    } catch (e) {
        console.error(`[timeline] failed to write: ${e}`);
    }
}
```

